const MACRO_TOPICS = [
  'Intelligenza Artificiale',
  'Cybersecurity',
  'Business & Finanza',
  'Politica & Geopolitica',
  'Startup & Innovazione',
  'Software & Sviluppo',
  'Scienza & Ricerca',
  'Energia & Ambiente',
  'Economia & Mercati',
  'Social Media & Cultura',
  'Salute & Medicina',
  'Trasporti & Mobilità'
];

const articles = $input.all().map(i => i.json);

const articleList = articles.map((a, i) => {
  const title = String(a.title || '').trim();
  // content è già pulito da HTML dalla fase di enrichment
  const content = String(a.content || a.contentSnippet || '').trim().substring(0, 500);
  const source = String(a.source || a.__sourceName || '').trim();
  const pubDate = String(a.pubDate || a.isoDate || '').trim();
  const url = String(a.url || '').trim();
  const uniqueKey = String(a.uniqueKey || a._id || `article-${i + 1}`).trim();

  return [
    `[${i + 1}] UNIQUEKEY: ${uniqueKey}`,
    `TITOLO: ${title}`,
    `FONTE: ${source}`,
    `DATA: ${pubDate}`,
    `CONTENUTO: ${content}`,
    `URL: ${url}`
  ].join('\n');
}).join('\n\n---\n\n');

const systemPrompt = `Sei un assistente di business intelligence. Analizza ogni articolo e restituisci SOLO un JSON array valido con questa struttura per ciascun articolo:
[
  {
    "index": <numero intero 1-based>,
    "uniqueKey": "<uniqueKey_esatto_dall_input>",
    "summary": "<riassunto in italiano max 50 parole>",
    "sentiment": "<Positive | Negative | Neutral>",
    "entities": ["<entita1>", "<entita2>"],
    "macroTopics": ["<topic_dalla_lista>"]
  }
]

REGOLA CRITICA per macroTopics:
- Scegli SOLO valori da questa lista: ${MACRO_TOPICS.join(', ')}
- Minimo 1, massimo 3 valori per articolo
- Non inventare mai topic nuovi o varianti
- Se nessun topic è pertinente, usa ["Scienza & Ricerca"]

REGOLA CRITICA per uniqueKey:
- Copia esattamente il valore UNIQUEKEY fornito nell'input
- Se non sei sicuro, usa comunque la stessa stringa mostrata nell'articolo

Nessun testo aggiuntivo. Nessun markdown. Solo JSON puro.`;

const userPrompt = `Analizza i seguenti ${articles.length} articoli:

${articleList}`;

return [{
  json: {
    articles,
    batchSize: articles.length,
    payload: {
      model: 'openrouter/free',
      max_tokens: 2500,
      temperature: 0.2,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    }
  }
}];

const VALID_TOPICS = new Set([
  'Intelligenza Artificiale',
  'Cybersecurity',
  'Business & Finanza',
  'Politica & Geopolitica',
  'Startup & Innovazione',
  'Software & Sviluppo',
  'Scienza & Ricerca',
  'Energia & Ambiente',
  'Economia & Mercati',
  'Social Media & Cultura',
  'Salute & Medicina',
  'Trasporti & Mobilità'
]);

const DEFAULT_TOPIC = ['Scienza & Ricerca'];

const prepareOutput = $('Prepare LLM Prompt').first().json;
const articles = prepareOutput.articles || [];
const llmRoot = $input.first().json;
const llmBody = llmRoot.body ?? llmRoot;
const statusCode = llmRoot.statusCode ?? llmBody?.statusCode ?? 200;

const results = [];

function sanitizeTopics(raw) {
  if (!Array.isArray(raw) || raw.length === 0) return DEFAULT_TOPIC;
  const valid = raw.filter(t => VALID_TOPICS.has(t));
  return valid.length > 0 ? valid : DEFAULT_TOPIC;
}

function cleanText(value) {
  return String(value || '')
    .replace(/```json|```/gi, '')
    .trim();
}

function getResponseContent(body) {
  if (!body) return '';
  if (typeof body === 'string') return body;
  if (typeof body === 'object') {
    return body.choices?.[0]?.message?.content
      ?? body.output_text
      ?? body.message?.content
      ?? '';
  }
  return '';
}

function extractJsonArray(raw) {
  const cleaned = cleanText(raw);
  const firstArray = cleaned.match(/\[[\s\S]*\]/);
  if (firstArray) return firstArray[0];
  return cleaned;
}

function fallbackSummary(article) {
  const candidate = String(
    article.contentSnippet ||
    article.content ||
    article.title ||
    ''
  ).replace(/\s+/g, ' ').trim();

  return candidate.substring(0, 300);
}

function buildFallback(errorMessage) {
  for (const article of articles) {
    results.push({
      json: {
        _id: article._id,
        uniqueKey: article.uniqueKey,
        summary: fallbackSummary(article),
        sentiment: 'Neutral',
        entities: [],
        macroTopics: DEFAULT_TOPIC,
        aiProcessed: false,
        aiError: errorMessage,
        processedAt: new Date().toISOString(),
        status: 'processed'
      }
    });
  }
  return results;
}

const rawContent = getResponseContent(llmBody);

if (statusCode !== 200 || !rawContent) {
  console.warn('[BriefAI W2] Fallback attivato. HTTP status:', statusCode);
  return buildFallback(`HTTP ${statusCode} — LLM non disponibile`);
}

let parsed = [];
try {
  const jsonText = extractJsonArray(rawContent);
  parsed = JSON.parse(jsonText);
  if (!Array.isArray(parsed)) throw new Error('Risposta non è un array JSON');
} catch (e) {
  console.error('[BriefAI W2] JSON parse error:', e.message);
  return buildFallback('JSON parse error: ' + e.message);
}

const aiByIndex = {};
const aiByKey = {};

for (const item of parsed) {
  if (!item || typeof item !== 'object') continue;
  if (Number.isInteger(item.index)) aiByIndex[item.index] = item;
  if (typeof item.uniqueKey === 'string' && item.uniqueKey.trim()) {
    aiByKey[item.uniqueKey.trim()] = item;
  }
}

for (let i = 0; i < articles.length; i++) {
  const article = articles[i];
  const ai = aiByKey[String(article.uniqueKey || '').trim()] || aiByIndex[i + 1] || {};

  const summary = String(ai.summary || fallbackSummary(article)).replace(/\s+/g, ' ').trim().substring(0, 300);
  const sentiment = ['Positive', 'Negative', 'Neutral'].includes(ai.sentiment) ? ai.sentiment : 'Neutral';

  results.push({
    json: {
      _id: article._id,
      uniqueKey: article.uniqueKey,
      summary,
      sentiment,
      entities: Array.isArray(ai.entities) ? ai.entities : [],
      macroTopics: sanitizeTopics(ai.macroTopics),
      aiProcessed: true,
      aiError: null,
      processedAt: new Date().toISOString(),
      status: 'processed'
    }
  });
}

return results;

const count = $input.all().length;
console.log('[BriefAI W2] ✅ Batch LLM elaborato: ' + count + ' articoli → processed.');
return $input.all();

const httpRes = $input.first().json;
const article = $('IF — Is Reuters?').first().json;

let content = '';
let enrichmentOk = false;

const statusCode = httpRes.statusCode || 0;
const rawBody = typeof httpRes.body === 'string'
  ? httpRes.body
  : (httpRes.body ? JSON.stringify(httpRes.body) : '');

function decodeHtmlEntities(str) {
  return String(str || '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&#x27;/g, "'")
    .replace(/&#10;/g, ' ')
    .replace(/&#13;/g, ' ');
}

function cleanText(str) {
  return decodeHtmlEntities(str)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<header[\s\S]*?<\/header>/gi, ' ')
    .replace(/<nav[\s\S]*?<\/nav>/gi, ' ')
    .replace(/<footer[\s\S]*?<\/footer>/gi, ' ')
    .replace(/<aside[\s\S]*?<\/aside>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

if (statusCode >= 200 && statusCode < 400 && rawBody.length > 300) {
  try {
    const text = cleanText(rawBody);

    if (text.length > 300) {
      content = text.substring(0, 3000);
      enrichmentOk = true;
      console.log('[BriefAI W2] ✅ Reuters arricchito (' + text.length + ' chars): ' + (article.title || '').substring(0, 60));
    } else {
      console.warn('[BriefAI W2] ⚠️ Testo troppo corto (' + text.length + ' chars), fallback necessario.');
    }
  } catch (e) {
    console.error('[BriefAI W2] ❌ Errore estrazione Reuters:', e.message);
  }
} else {
  console.warn('[BriefAI W2] ⚠️ HTTP ' + statusCode + ' per ' + (article.url || ''));
}

if (!enrichmentOk) {
  let fallback = article.contentSnippet || article.content || '';
  fallback = cleanText(fallback);

  if (!fallback || fallback.length < 50) {
    const title = (article.title || '').trim();
    const source = (article.source || '').trim();
    fallback = `${title}. (${source}) Notizia recente: ${title.toLowerCase()}.`;
  }

  content = fallback;
  console.warn('[BriefAI W2] 🔄 Fallback usato: ' + (article.title || '').substring(0, 60));
}

return [{
  json: {
    ...article,
    content,
    status: 'ready',
    enrichedAt: new Date().toISOString(),
    enrichmentOk
  }
}];

const httpRes  = $input.first().json;
const article  = $('IF \u2014 Is Hacker News?1').first().json;

let content      = '';
let enrichmentOk = false;

const statusCode = httpRes.statusCode || 0;
const rawBody    = typeof httpRes.body === 'string'
  ? httpRes.body
  : (httpRes.body ? JSON.stringify(httpRes.body) : '');

function decodeHtmlEntities(str) {
  return String(str || '')
    .replace(/&nbsp;/g,  ' ')
    .replace(/&amp;/g,   '&')
    .replace(/&lt;/g,    '<')
    .replace(/&gt;/g,    '>')
    .replace(/&quot;/g,  '"')
    .replace(/&#39;/g,   "'")
    .replace(/&#x27;/g,  "'")
    .replace(/&#10;/g,   ' ')
    .replace(/&#13;/g,   ' ');
}

function cleanText(str) {
  return decodeHtmlEntities(str)
    .replace(/<script[\s\S]*?<\/script>/gi,     ' ')
    .replace(/<style[\s\S]*?<\/style>/gi,       ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<header[\s\S]*?<\/header>/gi,     ' ')
    .replace(/<nav[\s\S]*?<\/nav>/gi,           ' ')
    .replace(/<footer[\s\S]*?<\/footer>/gi,     ' ')
    .replace(/<aside[\s\S]*?<\/aside>/gi,       ' ')
    .replace(/<!--[\s\S]*?-->/g,                ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

if (statusCode >= 200 && statusCode < 400 && rawBody.length > 300) {
  try {
    const text = cleanText(rawBody);
    if (text.length > 300) {
      content      = text.substring(0, 3000);
      enrichmentOk = true;
      console.log('[BriefAI W2] \u2705 HN arricchito (' + text.length + ' chars): ' + (article.title || '').substring(0, 60));
    } else {
      console.warn('[BriefAI W2] \u26a0\ufe0f Testo HN troppo corto (' + text.length + ' chars), uso fallback.');
    }
  } catch (e) {
    console.error('[BriefAI W2] \u274c Errore estrazione HN:', e.message);
  }
} else {
  console.warn('[BriefAI W2] \u26a0\ufe0f HTTP ' + statusCode + ' per HN url: ' + (article.url || ''));
}

if (!enrichmentOk) {
  let fallback = article.contentSnippet || article.content || '';
  fallback = cleanText(fallback);
  if (!fallback || fallback.length < 50) {
    const title  = (article.title  || '').trim();
    const source = (article.source || '').trim();
    fallback = title + '. (' + source + ') ' + title.toLowerCase() + '.';
  }
  content = fallback;
  console.warn('[BriefAI W2] \ud83d\udd04 Fallback HN usato: ' + (article.title || '').substring(0, 60));
}

return [{
  json: {
    ...article,
    content,
    status:      'ready',
    enrichedAt:  new Date().toISOString(),
    enrichmentOk
  }
}];

// Articolo non-Reuters: pulisci il content da eventuale HTML e segna come ready
return $input.all().map(item => {
  const raw = item.json.content || item.json.contentSnippet || item.json.title || '';
  const cleanContent = raw
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  return {
    json: {
      ...item.json,
      content: cleanContent || item.json.title || '',
      status: 'ready'
    }
  };
});
